            h += "<tr><td style='color:#333;font-weight:700'>AVERAGE</td><td style='font-weight:700'>" + avgS2 + "/" + avgD2 + "</td><td>" + avgP2 + "</td><td colspan='3' style='font-style:italic'>" + rBPr.length + " total</td></tr>";
