    if (has(["arrested","taken into custody","booked","charged with","taken to jail"])) return { formType: "sir", reason: "Consumer arrested — SIR" };
    if (has(["transportation incident","vehicle accident","car accident","auto accident","bus accident","van accident"])) return { formType: "sir", reason: "Transportation incident — SIR" };
    if (has(["choking","choked","airway obstruction","heimlich","stopped breathing","not breathing"])) return { formType: "sir", reason: "Choking requiring intervention — SIR" };
